def number_to_letters(n: int) -> str:
    """Convert 1->a, 2->b, ..., 26->z, 27->aa, etc."""
    result = ""
    while n:
        n -= 1
        result = chr(ord('a') + n % 26) + result
        n //= 26
    return result


def remove_comments(text: str) -> str:
    """Remove unescaped % and everything after it on each line."""
    text = text.replace('\\%', '\x00ESCAPED\x00')
    lines = []
    for line in text.split('\n'):
        i = line.find('%')
        if i != -1:
            lines.append(line[:i])
        else:
            lines.append(line)
    return '\n'.join(lines).replace('\x00ESCAPED\x00', '%')


def extract_preamble_and_body(text: str):
    """Extract preamble (before \\begin{document}) and body (after)."""
    m = re.search(r'\\begin\{document\}', text)
    n = re.search(r'\\end\{document\}', text)
    if m and n:
        return text[:m.start()], text[m.end():n.start()]
    return '', text


def extract_body(text: str) -> str:
    """Extract the body text (between \\begin{document} and \\end{document})."""
    return extract_preamble_and_body(text)[1]


MACRO_PATTERNS = [
    (r'\\def\\(\w+)\{([^}]+)\}', 1, 2),
    (r'\\newcommand{\\(\w+)}\{([^}]+)\}', 1, 2),
]


def extract_macros(text: str) -> dict[str, str]:
    """Extract parameter-free macro definitions from preamble."""
    macros = {}
    for pattern, name_idx, repl_idx in MACRO_PATTERNS:
        for match in re.finditer(pattern, text):
            macros[match.group(name_idx)] = match.group(repl_idx)
    return macros


def detect_macro_cycles(macros: dict[str, str]) -> bool:
    """Detect cycles in macro definitions using DFS."""
    visited = set()
    rec_stack = set()

    def dfs(cmd):
        if cmd in rec_stack:
            return True
        if cmd in visited:
            return False
        visited.add(cmd)
        rec_stack.add(cmd)
        for match in re.finditer(r'\\(\w+)', macros.get(cmd, '')):
            ref = match.group(1)
            if ref in macros and dfs(ref):
                return True
        rec_stack.remove(cmd)
        return False

    return any(cmd not in visited and dfs(cmd) for cmd in macros)


