#!/usr/bin/env python3
"""LaTeX to KaTeX-compatible Markdown converter."""

import argparse
import re
import sys
from pathlib import Path


def number_to_letters(n: int) -> str:
    """Convert 1->a, 2->b, ..., 26->z, 27->aa, etc."""
    result = ""
    while n:
        n -= 1
        result = chr(ord('a') + n % 26) + result
        n //= 26
    return result


def remove_comments(text: str) -> str:
    """Remove unescaped % and everything after it on each line."""
    text = text.replace('\\%', '\x00ESCAPED\x00')
    lines = []
    for line in text.split('\n'):
        i = line.find('%')
        if i != -1:
            lines.append(line[:i])
        else:
            lines.append(line)
    return '\n'.join(lines).replace('\x00ESCAPED\x00', '%')


def extract_preamble_and_body(text: str):
    """Extract preamble (before \\begin{document}) and body (after)."""
    m = re.search(r'\\begin\{document\}', text)
    n = re.search(r'\\end\{document\}', text)
    if m and n:
        return text[:m.start()], text[m.end():n.start()]
    return '', text


def extract_body(text: str) -> str:
    """Extract the body text (between \\begin{document} and \\end{document})."""
    return extract_preamble_and_body(text)[1]


MACRO_PATTERNS = [
    (r'\\def\\(\w+)\{([^}]+)\}', 1, 2),
    (r'\\newcommand{\\(\w+)}\{([^}]+)\}', 1, 2),
]


def extract_macros(text: str) -> dict[str, str]:
    """Extract parameter-free macro definitions from preamble."""
    macros = {}
    for pattern, name_idx, repl_idx in MACRO_PATTERNS:
        for match in re.finditer(pattern, text):
            macros[match.group(name_idx)] = match.group(repl_idx)
    return macros


def detect_macro_cycles(macros: dict[str, str]) -> bool:
    """Detect cycles in macro definitions using DFS."""
    visited = set()
    rec_stack = set()

    def dfs(cmd):
        if cmd in rec_stack:
            return True
        if cmd in visited:
            return False
        visited.add(cmd)
        rec_stack.add(cmd)
        for match in re.finditer(r'\\(\w+)', macros.get(cmd, '')):
            ref = match.group(1)
            if ref in macros and dfs(ref):
                return True
        rec_stack.remove(cmd)
        return False

    return any(cmd not in visited and dfs(cmd) for cmd in macros)


def expand_macros(text: str, macros: dict[str, str], max_iter: int = 100) -> str:
    """Expand macros in text until no more changes."""
    # Pre-expand macro definitions in replacement strings (handle chaining)
    changed = True
    while changed:
        changed = False
        for name, repl in list(macros.items()):
            # Expand macros in replacement string
            def expand(m, macros=macros):
                inner = m.group(1)
                return macros.get(inner) if inner in macros else m.group(0)
            new_repl = re.sub(r'\\(\w+)(?![a-zA-Z])', expand, repl)
            if new_repl != repl:
                macros[name] = new_repl
                changed = True

    # Apply expansions to text
    for _ in range(max_iter):
        curr = text
        for name, repl in macros.items():
            curr = re.sub(r'\\' + re.escape(name) + r'(?![a-zA-Z])', repl, curr)
        if curr == text:
            break
        text = curr
    return text


def strip_whitespace(text: str) -> str:
    return '\n'.join(line.strip() for line in text.split('\n'))


def convert_display_math(text: str) -> str:
    result = []
    i = 0
    while i < len(text):
        open_pos = text.find('\\[', i)
        if open_pos == -1:
            result.append(text[i:])
            break
        result.append(text[i:open_pos])
        close_pos = text.find('\\]', open_pos + 2)
        if close_pos == -1:
            result.append(text[open_pos:])
            break
        result.append('\n$$\n' + text[open_pos + 2:close_pos] + '\n$$\n')
        i = close_pos + 2
    return ''.join(result)


def convert_sections_and_formatting(text: str) -> str:
    text = re.sub(r'\\section\{([^}]+)\}', r'## \1', text)
    text = re.sub(r'\\subsection\{([^}]+)\}', r'### \1', text)
    text = re.sub(r'\\subsubsection\{([^}]+)\}', r'#### \1', text)
    text = re.sub(r'\\emph\{([^}]*)\}', r'_\1_', text)
    text = re.sub(r'\\textbf\{([^}]*)\}', r'**\1**', text)
    return text


def delete_commands(text: str) -> str:
    return (re.sub(r'\\vspace\{[^}]*\}', '', text)
            .replace(r'\medskip', '')
            .replace(r'\smallskip', '')
            .replace(r'\bigskip', ''))


def normalize_blanks(text: str) -> str:
    return re.sub(r'\n{3,}', '\n\n', text)


def convert_includegraphics(text: str) -> str:
    if re.search(r'\\includegraphics(?:\[[^\]]*\])?\{\s*\}', text):
        print("Error: malformed includegraphics command", file=sys.stderr)
        sys.exit(1)
    return re.sub(r'\\includegraphics(?:\[[^\]]*\])?\{([^}]+)\}', r'![image](\1)', text)


def unwrap_environments(text: str) -> str:
    return (re.sub(r'\\begin\{multicols\}\{[^}]*\}', '', text)
            .replace(r'\end{multicols}', '')
            .replace(r'\begin{minipage}{', '')
            .replace(r'\end{minipage}', ''))


def convert_parbox(text: str) -> str:
    return re.sub(r'\\parbox\{[^}]+\}\{([^}]+)\}', r'\1', text)


def convert_np_macro(text: str) -> str:
    return re.sub(r'\\np\{([^}]+)\}', r'\1', text)


def parse_enumerate_options(line: str) -> tuple[int | None, bool]:
    m = re.match(r'\\begin\{enumerate\}(.*)$', line)
    if not m:
        return None, False
    opts = m.group(1).strip()
    if not opts:
        return 1, False
    sm = re.match(r'^\[(start=)(\d+)\]$', opts)
    if sm:
        return int(sm.group(2)), False
    return None, True


def process_items(content: str, list_type: str = 'enumerate', is_nested: bool = False,
                  start_num: int = 1, parent_num: int | None = None) -> tuple[list[str], int | None]:
    """Process itemize/enumerate content. Returns (lines, error_code)."""
    lines = []
    pos = 0
    item_idx = 0

    while pos < len(content):
        # Find next item
        ms = re.search(r'\\item(?:\[.*?\])?', content[pos:])
        if not ms:
            if content[pos:].strip():
                lines.append(content[pos:].strip())
            break

        # Add any text before this item
        before = content[pos:pos + ms.start()].strip()
        if before:
            lines.append(before)

        pos += ms.end()

        # Find nested environment
        ns = re.search(r'\\begin\{(enumerate|itemize)\}', content[pos:])
        ne = re.search(r'\\end\{(?:enumerate|itemize)\}', content[pos:])
        has_nested = ns and (not ne or ns.start() < ne.start())

        if has_nested:
            if is_nested and ns.group(1) == 'enumerate':
                return [], 1

            env_type = ns.group(1)
            start = pos + ns.end()
            depth = 1
            j = start
            while j < len(content) and depth:
                er = re.search(r'\\end\{(enumerate|itemize)\}', content[j:])
                sr = re.search(r'\\begin\{(enumerate|itemize)\}', content[j:])
                if not er:
                    break
                if sr and sr.start() < er.start():
                    depth += 1
                    j += sr.end()
                else:
                    depth -= 1
                    j += er.end()

            nested = content[start:j - (er.end() if er else 0)]

            if env_type == 'enumerate':
                child, err = process_items(nested, True, start_num, item_idx + 1)
            else:
                child, err = process_items(nested, 'itemize', False)
            if err:
                return [], err
            lines.extend(child)
            pos = j
            continue

        # Extract item content (up to next \\item or end)
        ni = re.search(r'\\item(?:\[.*?\])', content[pos:])
        item_content = content[pos:pos + ni.start()] if ni else content[pos:]
        item_content = item_content.strip()

        if list_type == 'itemize':
            lines.append(f'-   {item_content}')
        elif is_nested and parent_num:
            lines.append(f'**{parent_num}.{number_to_letters(item_idx + 1)})** {item_content}')
        else:
            lines.append(f'**{start_num}.** {item_content}')
            start_num += 1

        item_idx += 1
        pos += ni.start() if ni else len(item_content)

    return lines, None


def convert_latex_to_markdown(input_text: str) -> str:
    """Convert LaTeX source to Markdown."""
    # Step 1: Remove comments (escaped % must be handled first)
    text = remove_comments(input_text)

    # Step 2: Extract preamble and body
    preamble, body = extract_preamble_and_body(text)

    # Step 3: Extract and validate macros from preamble
    macros = extract_macros(preamble)
    if detect_macro_cycles(macros):
        print("Error: cyclic macro definition", file=sys.stderr)
        sys.exit(1)

    # Step 4: Apply environment unwrapping to body (before macro expansion)
    body = unwrap_environments(body)

    # Step 5: Convert parbox commands
    body = convert_parbox(body)

    # Step 6: Convert includegraphics
    body = convert_includegraphics(body)

    # Step 7: Convert np macro
    body = convert_np_macro(body)

    # Step 8: Expand macros in the body
