    """Convert 1->a, 2->b, ..., 26->z, 27->aa, etc."""
    result = ""
    while n:
        n -= 1
        result = chr(ord('a') + n % 26) + result
        n //= 26
    return result


def remove_comments(text: str) -> str:
    """Remove unescaped % and everything after it on each line."""
    text = text.replace('\\%', '\x00ESCAPED\x00')
    lines = []
    for line in text.split('\n'):
        i = line.find('%')
        if i != -1:
            lines.append(line[:i])
        else:
            lines.append(line)
    return '\n'.join(lines).replace('\x00ESCAPED\x00', '%')


def extract_preamble_and_body(text):
    """Extract preamble (before \\begin{document}) and body (after)."""
    m = re.search(r'\\begin\{document\}', text)
    n = re.search(r'\\end\{document\}', text)
    if m and n:
        return text[:m.start()], text[m.end():n.start()]
    return '', text


def extract_body(text: str) -> str:
    """Extract the body text (between \\begin{document} and \\end{document})."""
    return extract_preamble_and_body(text)[1]


MACRO_PATTERNS = [
    (r'\\def\\(\w+)\{([^}]+)\}', 1, 2),
    (r'\\newcommand{\\(\w+)}\{([^}]+)\}', 1, 2),
]


def extract_macros(text: str) -> dict[str, str]:
    """Extract parameter-free macro definitions from preamble."""
    macros = {}
    for pattern, name_idx, repl_idx in MACRO_PATTERNS:
        for match in re.finditer(pattern, text):
            macros[match.group(name_idx)] = match.group(repl_idx)
    return macros


def detect_macro_cycles(macros: dict[str, str]) -> bool:
    """Detect cycles in macro definitions using DFS."""
    visited = set()
    rec_stack = set()

    def dfs(cmd):
        if cmd in rec_stack:
            return True
        if cmd in visited:
            return False
        visited.add(cmd)
        rec_stack.add(cmd)
        for match in re.finditer(r'\\(\w+)', macros.get(cmd, '')):
            ref = match.group(1)
            if ref in macros and dfs(ref):
                return True
        rec_stack.remove(cmd)
        return False

    return any(cmd not in visited and dfs(cmd) for cmd in macros)


def _resolve_macro(cmd: str, macros: dict[str, str]) -> str:
    """Resolve a macro to its final expansion."""
    visited = set()
    while cmd in macros:
        if cmd in visited:
            return '\\' + cmd
        visited.add(cmd)
        # Check if replacement starts with a macro reference
        m = re.match(r'\\(\w+)(?![a-zA-Z])', macros[cmd])
        if m:
            cmd = m.group(1)
        else:
            return macros[cmd]
    return '\\' + cmd


def expand_macros(text: str, macros: dict[str, str], max_iter: int = 100) -> str:
    """Expand macros in text until no more changes."""
    # Pre-resolve all macros once
    resolved = {name: _resolve_macro(name, macros) for name in macros}

    # Apply expansions until no changes
    for _ in range(max_iter):
        curr = text
        for name, repl in resolved.items():
            curr = re.sub(r'\\' + re.escape(name) + r'(?![a-zA-Z])', repl, curr)
        if curr == text:
            break
        text = curr
    return text


def strip_whitespace(text: str) -> str:
    return '\n'.join(line.strip() for line in text.split('\n'))


def convert_display_math(text: str) -> str:
    result = []
    i = 0
    while i < len(text):
        open_pos = text.find('\\[', i)
        if open_pos == -1:
            result.append(text[i:])
            break
        result.append(text[i:open_pos])
        close_pos = text.find('\\]', open_pos + 2)
        if close_pos == -1:
            result.append(text[open_pos:])
            break
        result.append('\n$$\n' + text[open_pos + 2:close_pos] + '\n$$\n')
        i = close_pos + 2
    return ''.join(result)


def convert_sections_and_formatting(text: str) -> str:
    text = re.sub(r'\\section\{([^}]+)\}', r'## \1', text)
    text = re.sub(r'\\subsection\{([^}]+)\}', r'### \1', text)
    text = re.sub(r'\\subsubsection\{([^}]+)\}', r'#### \1', text)
    text = re.sub(r'\\emph\{([^}]*)\}', r'_\1_', text)
    text = re.sub(r'\\textbf\{([^}]*)\}', r'**\1**', text)
    return text


def delete_commands(text: str) -> str:
    return (re.sub(r'\\vspace\{[^}]*\}', '', text)
            .replace(r'\medskip', '')
            .replace(r'\smallskip', '')
            .replace(r'\bigskip', ''))


def normalize_blanks(text: str) -> str:
    return re.sub(r'\n{3,}', '\n\n', text)


def convert_includegraphics(text: str) -> str:
    if re.search(r'\\includegraphics(?:\[[^\]]*\])?\{\s*\}', text):
